content:
{
  "sentences": [
    {
      "text": "我的公寓有一個大客廳。",
      "pinyin": "Wǒ de gōngyù yǒu yī ge dà kètīng.",
      "pinyin_numeric": "wo3 de0 gong1yu4 you3 yi1 ge0 da4 ke4ting1.",
      "translation_en": "My apartment has a big living room.",
      "translation_ko": "제 아파트에는 큰 거실이 있습니다."
    },
    {
      "text": "房間裡有兩張床和一個衣櫃。",
      "pinyin": "Fángjiān lǐ yǒu liǎng zhāng chuáng hé yī ge yīguì.",
      "pinyin_numeric": "fang2jian1 li3 you3 liang3 zhang1 chuang2 he2 yi1 ge0 yi1gui4.",
      "translation_en": "There are two beds and a wardrobe in the room.",
      "translation_ko": "방 안에는 침대 두 개와 옷장 하나가 있습니다."
    },
    {
      "text": "廚房裡有冰箱、水槽和熱水器。",
      "pinyin": "Chúfáng lǐ yǒu bīngxiāng, shuǐcáo hé rèshuǐqì.",
      "pinyin_numeric": "chu2fang2 li3 you3 bing1xiang1, shui3cao2 he2 re4shui3qi4.",
      "translation_en": "The kitchen has a refrigerator, a sink, and a water heater.",
      "translation_ko": "부엌에는 냉장고, 싱크대, 온수기가 있습니다."
    },
    {
      "text": "浴室裡有馬桶和一個小窗戶。",
      "pinyin": "Yùshì lǐ yǒu mǎtǒng hé yī ge xiǎo chuānghù.",
      "pinyin_numeric": "yu4shi4 li3 you3 ma3tong3 he2 yi1 ge0 xiao3 chuang1hu4.",
      "translation_en": "The bathroom has a toilet and a small window.",
      "translation_ko": "욕실에는 변기와 작은 창문이 있습니다."
    },
    {
      "text": "客廳沒有沙發，但是有兩張桌子。",
      "pinyin": "Kètīng méiyǒu shāfā, dànshì yǒu liǎng zhāng zhuōzi.",
      "pinyin_numeric": "ke4ting1 mei2you3 sha1fa1, dan4shi4 you3 liang3 zhang1 zhuo1zi0.",
      "translation_en": "The living room doesn't have a sofa, but it has two tables.",
      "translation_ko": "거실에는 소파가 없지만 테이블이 두 개 있습니다."
    },
    {
      "text": "我的房間有書桌和燈，所以很明亮。",
      "pinyin": "Wǒ de fángjiān yǒu shūzhuō hé dēng, suǒyǐ hěn míngliàng.",
      "pinyin_numeric": "wo3 de0 fang2jian1 you3 shu1zhuo1 he2 deng1, suo3yi3 hen3 ming2liang4.",
      "translation_en": "My room has a desk and a lamp, so it's very bright.",
      "translation_ko": "제 방에는 책상과 등이 있어서 매우 밝습니다."
    },
    {
      "text": "陽台上有洗衣機和一個小椅子。",
      "pinyin": "Yángtái shàng yǒu xǐyījī hé yī ge xiǎo yǐzi.",
      "pinyin_numeric": "yang2tai2 shang4 you3 xi3yi1ji1 he2 yi1 ge0 xiao3 yi3zi0.",
      "translation_en": "There is a washing machine and a small chair on the balcony.",
      "translation_ko": "발코니에는 세탁기와 작은 의자가 있습니다."
    },
    {
      "text": "公寓的門前面有一個大窗戶。",
      "pinyin": "Gōngyù de mén qiánmiàn yǒu yī ge dà chuānghù.",
      "pinyin_numeric": "gong1yu4 de0 men2 qian2mian4 you3 yi1 ge0 da4 chuang1hu4.",
      "translation_en": "There is a big window in front of the apartment door.",
      "translation_ko": "아파트 문 앞에는 큰 창문이 있습니다."
    },
    {
      "text": "廚房的水槽旁邊有插座和開關。",
      "pinyin": "Chúfáng de shuǐcáo pángbiān yǒu chāzuò hé kāiguān.",
      "pinyin_numeric": "chu2fang2 de0 shui3cao2 pang2bian1 you3 cha1zuo4 he2 kai1guan1.",
      "translation_en": "Next to the kitchen sink, there are an outlet and a switch.",
      "translation_ko": "부엌 싱크대 옆에는 콘센트와 스위치가 있습니다."
    },
    {
      "text": "浴室沒有窗戶，但是有冷氣。",
      "pinyin": "Yùshì méiyǒu chuānghù, dànshì yǒu lěngqì.",
      "pinyin_numeric": "yu4shi4 mei2you3 chuang1hu4, dan4shi4 you3 leng3qi4.",
      "translation_en": "The bathroom doesn't have a window, but it has air conditioning.",
      "translation_ko": "욕실에는 창문이 없지만 에어컨이 있습니다."
    }
  ]
}
